public int maxRotateFunction(int[] nums) {
    int n = nums.length;
    int total_sum = 0;
    int f = 0;

    for (int i = 0; i < n; i++) {
        total_sum += nums[i];
        f += i * nums[i];
    }

    int max_f = f;
    for (int i = 1; i < n; i++) {
        f += total_sum - (n * nums[n - i]);
        max_f = Math.max(max_f, f);
    }

    return max_f;
}
```


